def splitPainting(segments):
    line = {}
    for s in segments:
        start, end, color = s
        if start not in line:
            line[start] = 0
        if end not in line:
            line[end] = 0
        line[start] += color
        line[end] -= color
    res = []
    pre = 0
    sum = 0
    for key in sorted(line.keys()):
        if pre > 0:
            if sum > 0:
                res.append([pre, key, sum])
        pre = key
        sum += line[key]
    return res
